mapper.select:
SELECT id, post_id AS postId, user_id AS userId, content, parent_id AS parentId,
       reply_to_user_id AS replyToUserId, status, created_at AS createdAt
FROM comments WHERE id = #{id}

SELECT c.id, c.post_id AS postId, c.user_id AS userId, c.content, c.parent_id AS parentId, c.reply_to_user_id AS replyToUserId, c.created_at AS createdAt, u.nickname, u.avatar, (SELECT COUNT(1) FROM comments r WHERE r.parent_id = c.id AND r.status = 1) AS replyCount FROM comments c JOIN users u ON u.id = c.user_id WHERE c.post_id = #{postId} AND c.parent_id IS NULL AND c.status = 1
AND (c.created_at, c.id) < (#{createdAt}, #{id})
ORDER BY c.created_at DESC, c.id DESC LIMIT #{size}

SELECT c.id, c.post_id AS postId, c.user_id AS userId, c.content, c.parent_id AS parentId, c.reply_to_user_id AS replyToUserId, c.created_at AS createdAt, u.nickname, u.avatar, ru.nickname AS replyToNickname FROM comments c JOIN users u ON u.id = c.user_id LEFT JOIN users ru ON ru.id = c.reply_to_user_id WHERE c.parent_id = #{parentId} AND c.status = 1
AND (c.created_at, c.id) < (#{createdAt}, #{id})
ORDER BY c.created_at ASC, c.id ASC LIMIT #{size}
